SELECT 
    t.id, t.student_id, t.type, t.amount, t.notes, t.transaction_time,
    COALESCE(u.real_name, u.username) AS student_name,
    u.username AS student_username
FROM transactions t
LEFT JOIN users u ON t.student_id = u.id



            AND t.student_id = #{request.params.studentId}


            AND t.type = #{request.params.type}


            AND ABS(t.amount) >= #{request.params.minAmount}


            AND ABS(t.amount) <= #{request.params.maxAmount}


            AND DATE(t.transaction_time) = #{request.params.transactionDate}


            AND DATE(t.transaction_time) >= #{request.params.startDate}


            AND DATE(t.transaction_time) <= #{request.params.endDate}



            AND u.campus_id = #{request.params.campusId}



ORDER BY t.transaction_time DESC
